export const dynamic = 'force-dynamic'

import { NextRequest, NextResponse } from 'next/server'
import type { Prisma } from '@prisma/client'
import { prisma } from '@/lib/prisma'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import { getSessionUser } from '@/lib/auth'

// Cache headers helper
function cacheHeaders(seconds: number) {
  return {
    'Cache-Control': `public, s-maxage=${seconds}, stale-while-revalidate=${seconds * 2}`,
  }
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url)
  const category = searchParams.get('category')
  const search = searchParams.get('search')
  const status = searchParams.get('status')

  const where: Prisma.MarketWhereInput = {}

  if (category && category !== 'All') {
    where.category = category
  }

  if (search) {
    where.OR = [
      { title: { contains: search, mode: 'insensitive' } },
      { description: { contains: search, mode: 'insensitive' } },
    ]
  }

  if (status === 'resolved') {
    where.resolved = true
  } else if (status === 'active') {
    where.resolved = false
  }

  const markets = await prisma.market.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    select: {
      id: true,
      title: true,
      description: true,
      category: true,
      imageUrl: true,
      endDate: true,
      resolved: true,
      outcome: true,
      multiplier: true,
      liquidity: true,
      optionYesLabel: true,
      optionNoLabel: true,
      creatorName: true,
      createdAt: true,
      bets: {
        select: {
          choice: true,
          coins: true,
        },
      },
      priceHistory: {
        orderBy: { timestamp: 'desc' },
        take: 1,
        select: {
          yesPrice: true,
          noPrice: true,
        },
      },
    },
  })

  const marketsWithOdds = markets.map((market) => {
    const yesVolume = market.bets
      .filter((b) => b.choice === 'YES')
      .reduce((sum, b) => sum + b.coins, 0)
    const noVolume = market.bets
      .filter((b) => b.choice === 'NO')
      .reduce((sum, b) => sum + b.coins, 0)
    const totalVolume = yesVolume + noVolume

    const liquidity = market.liquidity || DEFAULT_LIQUIDITY
    const { yesPrice, noPrice } = calculateLMSRPrice(yesVolume, noVolume, liquidity)

    return {
      id: market.id,
      title: market.title,
      description: market.description,
      category: market.category,
      imageUrl: market.imageUrl,
      endDate: market.endDate.toISOString(),
      resolved: market.resolved,
      outcome: market.outcome,
      yesPrice: Math.round(yesPrice * 100),
      noPrice: Math.round(noPrice * 100),
      volume: totalVolume,
      multiplier: market.multiplier,
      optionYesLabel: market.optionYesLabel,
      optionNoLabel: market.optionNoLabel,
      creatorName: market.creatorName,
      createdAt: market.createdAt.toISOString(),
    }
  })

  return NextResponse.json(marketsWithOdds, {
    headers: cacheHeaders(15),
  })
}

export async function POST(request: NextRequest) {
  try {
    const user = await getSessionUser()
    if (!user) {
      return NextResponse.json({ error: 'Please sign in to create a market' }, { status: 401 })
    }

    const body = await request.json()
    const { title, description, category, endDate, imageUrl, optionYesLabel, optionNoLabel } = body

    if (!title?.trim() || !description?.trim() || !endDate) {
      return NextResponse.json({ error: 'Title, description, and end date are required' }, { status: 400 })
    }

    const market = await prisma.market.create({
      data: {
        title: title.trim(),
        description: description.trim(),
        category: category || 'Trending',
        endDate: new Date(endDate),
        creatorName: user.name,
        optionYesLabel: optionYesLabel || 'Yes',
        optionNoLabel: optionNoLabel || 'No',
        imageUrl: imageUrl || null,
      },
    })

    await prisma.priceHistory.create({
      data: {
        marketId: market.id,
        yesPrice: 0.5,
        noPrice: 0.5,
      },
    })

    return NextResponse.json(market)
  } catch {
    return NextResponse.json({ error: 'Failed to create market' }, { status: 500 })
  }
}

export const dynamic = 'force-dynamic'

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import { getSessionUser } from '@/lib/auth'

function cacheHeaders(seconds: number) {
  return {
    'Cache-Control': `public, s-maxage=${seconds}, stale-while-revalidate=${seconds * 2}`,
  }
}

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const market = await prisma.market.findUnique({
      where: { id },
      select: {
        id: true,
        title: true,
        description: true,
        category: true,
        imageUrl: true,
        endDate: true,
        resolved: true,
        outcome: true,
        multiplier: true,
        liquidity: true,
        optionYesLabel: true,
        optionNoLabel: true,
        creatorName: true,
        createdAt: true,
        bets: {
          orderBy: { createdAt: 'desc' },
          select: {
            id: true,
            userName: true,
            coins: true,
            choice: true,
            price: true,
            createdAt: true,
          },
        },
        priceHistory: {
          orderBy: { timestamp: 'asc' },
          select: {
            timestamp: true,
            yesPrice: true,
            noPrice: true,
          },
        },
      },
    })

    if (!market) {
      return NextResponse.json({ error: 'Market not found' }, { status: 404 })
    }

    const yesVolume = market.bets
      .filter((b) => b.choice === 'YES')
      .reduce((sum, b) => sum + b.coins, 0)
    const noVolume = market.bets
      .filter((b) => b.choice === 'NO')
      .reduce((sum, b) => sum + b.coins, 0)
    const totalVolume = yesVolume + noVolume

    const liquidity = market.liquidity || DEFAULT_LIQUIDITY
    const { yesPrice, noPrice } = calculateLMSRPrice(yesVolume, noVolume, liquidity)

    return NextResponse.json(
      {
        id: market.id,
        title: market.title,
        description: market.description,
        category: market.category,
        imageUrl: market.imageUrl,
        endDate: market.endDate.toISOString(),
        resolved: market.resolved,
        outcome: market.outcome,
        yesPrice: Math.round(yesPrice * 100),
        noPrice: Math.round(noPrice * 100),
        volume: totalVolume,
        multiplier: market.multiplier,
        optionYesLabel: market.optionYesLabel,
        optionNoLabel: market.optionNoLabel,
        creatorName: market.creatorName,
        createdAt: market.createdAt.toISOString(),
        liquidity: market.liquidity,
        bets: market.bets.map((b) => ({
          ...b,
          createdAt: b.createdAt.toISOString(),
        })),
        priceHistory: market.priceHistory.map((ph) => ({
          timestamp: ph.timestamp.toISOString(),
          yesPrice: ph.yesPrice,
          noPrice: ph.noPrice,
        })),
      },
      { headers: cacheHeaders(15) }
    )
  } catch {
    return NextResponse.json({ error: 'Failed to fetch market' }, { status: 500 })
  }
}

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const user = await getSessionUser()
    if (!user) {
      return NextResponse.json({ error: 'Please sign in to resolve a market' }, { status: 401 })
    }

    const body = await request.json()
    const { resolved, outcome } = body

    const existing = await prisma.market.findUnique({ 
      where: { id },
      select: { creatorName: true },
    })
    if (!existing) {
      return NextResponse.json({ error: 'Market not found' }, { status: 404 })
    }
    if (existing.creatorName !== user.name) {
      return NextResponse.json({ error: 'Only the market creator can resolve this market' }, { status: 403 })
    }
    if (!['YES', 'NO'].includes(outcome)) {
      return NextResponse.json({ error: 'Invalid outcome' }, { status: 400 })
    }

    const market = await prisma.market.update({
      where: { id },
      data: {
        resolved: resolved !== undefined ? resolved : undefined,
        outcome: outcome || undefined,
      },
    })

    // Resolve: winners receive shares, losers forfeit their stake
    if (resolved && outcome) {
      const allBets = await prisma.bet.findMany({
        where: { marketId: id },
        select: {
          id: true,
          userName: true,
          choice: true,
          coins: true,
          price: true,
        },
      })
      const winningBets = allBets.filter((b) => b.choice === outcome)
      const losingBets = allBets.filter((b) => b.choice !== outcome)

      // Process winners: return stake as shares (1 share = $1)
      for (const bet of winningBets) {
        const betUser = await prisma.user.findUnique({
          where: { name: bet.userName },
          select: { id: true, coins: true, heldCoins: true },
        })
        if (betUser) {
          const shares = bet.price > 0 ? bet.coins / bet.price : bet.coins
          await prisma.user.update({
            where: { id: betUser.id },
            data: {
              coins: betUser.coins + shares,
              heldCoins: Math.max(0, betUser.heldCoins - bet.coins),
            },
          })
        }
      }

      // Process losers: forfeit stake (already deducted when bet was placed)
      for (const bet of losingBets) {
        const betUser = await prisma.user.findUnique({
          where: { name: bet.userName },
          select: { id: true, heldCoins: true },
        })
        if (betUser) {
          await prisma.user.update({
            where: { id: betUser.id },
            data: {
              heldCoins: Math.max(0, betUser.heldCoins - bet.coins),
            },
          })
        }
      }
    }

    return NextResponse.json(market)
  } catch {
    return NextResponse.json({ error: 'Failed to update market' }, { status: 500 })
  }
}

