import { NextResponse } from 'next/server'
import { getLeaderboard } from '@/lib/leaderboard'

function cacheHeaders(seconds: number) {
  return {
    'Cache-Control': `public, s-maxage=${seconds}, stale-while-revalidate=${seconds * 2}`,
  }
}

export async function GET() {
  try {
    const leaderboard = await getLeaderboard()
    return NextResponse.json(leaderboard, {
      headers: cacheHeaders(60),
    })
  } catch {
    return NextResponse.json({ error: 'Failed to load leaderboard' }, { status: 500 })
  }
}
import { prisma } from '@/lib/prisma'

const STARTING_COINS = 10000

export type LeaderboardEntry = {
  rank: number
  id: string
  name: string
  coins: number
  heldCoins: number
  netWorth: number
  profit: number
  profitPct: number
  totalVolume: number
  betCount: number
  activeBetCount: number
  wins: number
  losses: number
}

export async function getLeaderboard(): Promise<LeaderboardEntry[]> {
  const [users, bets] = await Promise.all([
    prisma.user.findMany({
      select: {
        id: true,
        name: true,
        coins: true,
        heldCoins: true,
      },
    }),
    prisma.bet.findMany({
      select: {
        userName: true,
        coins: true,
        choice: true,
        market: {
          select: {
            resolved: true,
            outcome: true,
          },
        },
      },
    }),
  ])

  const statsByName = new Map<
    string,
    Pick<LeaderboardEntry, 'totalVolume' | 'betCount' | 'activeBetCount' | 'wins' | 'losses'>
  >()

  for (const bet of bets) {
    const stats = statsByName.get(bet.userName) || {
      totalVolume: 0,
      betCount: 0,
      activeBetCount: 0,
      wins: 0,
      losses: 0,
    }

    stats.totalVolume += bet.coins
    stats.betCount += 1

    if (!bet.market.resolved) {
      stats.activeBetCount += 1
    } else if (bet.market.outcome === bet.choice) {
      stats.wins += 1
    } else {
      stats.losses += 1
    }

    statsByName.set(bet.userName, stats)
  }

  return users
    .map((user) => {
      const stats = statsByName.get(user.name) || {
        totalVolume: 0,
        betCount: 0,
        activeBetCount: 0,
        wins: 0,
        losses: 0,
      }
      const netWorth = user.coins + user.heldCoins
      const profit = netWorth - STARTING_COINS

      return {
        rank: 0,
        id: user.id,
        name: user.name,
        coins: user.coins,
        heldCoins: user.heldCoins,
        netWorth,
        profit,
        profitPct: (profit / STARTING_COINS) * 100,
        ...stats,
      }
    })
    .sort((a, b) => {
      if (b.netWorth !== a.netWorth) return b.netWorth - a.netWorth
      if (b.totalVolume !== a.totalVolume) return b.totalVolume - a.totalVolume
      return a.name.localeCompare(b.name)
    })
    .map((entry, index) => ({
      ...entry,
      rank: index + 1,
    }))
}

