import { createHmac, randomBytes, scryptSync, timingSafeEqual } from 'crypto'

export const SESSION_COOKIE = 'scius_session'
export const SESSION_MAX_AGE = 60 * 60 * 24 * 30

type SessionPayload = {
  userId: string
  name: string
  exp: number
}

function getSecret() {
  return process.env.AUTH_SECRET || process.env.NEXTAUTH_SECRET || 'local-dev-session-secret-change-me'
}

function base64Url(input: Buffer | string) {
  return Buffer.from(input).toString('base64url')
}

function signPayload(payload: string) {
  return createHmac('sha256', getSecret()).update(payload).digest('base64url')
}

function normalizeUsername(username: string) {
  return username.trim().replace(/\s+/g, '_').slice(0, 32)
}

export function validateUsername(username: string) {
  const normalized = normalizeUsername(username)
  if (!/^[a-zA-Z0-9_-]{3,32}$/.test(normalized)) {
    throw new Error('Username must be 3-32 characters and use only letters, numbers, _ or -')
  }
  return normalized
}

export function validatePassword(password: string) {
  if (password.length < 6) {
    throw new Error('Password must be at least 6 characters')
  }
}

export function hashPassword(password: string) {
  const salt = randomBytes(16).toString('base64url')
  const hash = scryptSync(password, salt, 64).toString('base64url')
  return `scrypt:${salt}:${hash}`
}

export function verifyPassword(password: string, storedHash: string | null) {
  if (!storedHash) return false
  const [scheme, salt, hash] = storedHash.split(':')
  if (scheme !== 'scrypt' || !salt || !hash) return false

  const actual = Buffer.from(scryptSync(password, salt, 64).toString('base64url'))
  const expected = Buffer.from(hash)
  return actual.length === expected.length && timingSafeEqual(actual, expected)
}

export function createSessionToken(payload: Omit<SessionPayload, 'exp'>) {
  const body = base64Url(JSON.stringify({ ...payload, exp: Math.floor(Date.now() / 1000) + SESSION_MAX_AGE }))
  return `${body}.${signPayload(body)}`
}

export function verifySessionToken(token: string | undefined) {
  if (!token) return null

  const [body, signature] = token.split('.')
  if (!body || !signature || signPayload(body) !== signature) return null

  try {
    const payload = JSON.parse(Buffer.from(body, 'base64url').toString('utf8')) as SessionPayload
    if (!payload.userId || payload.exp < Math.floor(Date.now() / 1000)) return null
    return payload
  } catch {
    return null
  }
}

