import { cookies } from 'next/headers'
import { prisma } from '@/lib/prisma'
export {
  SESSION_COOKIE,
  SESSION_MAX_AGE,
  createSessionToken,
  hashPassword,
  validatePassword,
  validateUsername,
  verifyPassword,
} from '@/lib/auth-core'
import { SESSION_COOKIE, SESSION_MAX_AGE, createSessionToken, verifySessionToken } from '@/lib/auth-core'

export async function setSession(user: { id: string; name: string }) {
  const cookieStore = await cookies()
  cookieStore.set(SESSION_COOKIE, createSessionToken({ userId: user.id, name: user.name }), {
    httpOnly: true,
    sameSite: 'lax',
    secure: process.env.NODE_ENV === 'production',
    path: '/',
    maxAge: SESSION_MAX_AGE,
  })
}

export async function clearSession() {
  const cookieStore = await cookies()
  cookieStore.delete(SESSION_COOKIE)
}

export async function getSessionUser() {
  const cookieStore = await cookies()
  const token = cookieStore.get(SESSION_COOKIE)?.value
  const payload = verifySessionToken(token)
  if (!payload) return null

  return prisma.user.findUnique({
    where: { id: payload.userId },
    select: { id: true, name: true, coins: true, heldCoins: true },
  })
}

