  .patch('/api/markets/:id', async ({ body, params, request, set }) => {
    try {
      const user = await getSessionUser(request)
      if (!user) {
        set.status = 401
        return { error: 'Please sign in to resolve a market' }
      }

      const data = asObject(body)
      const outcome = getString(data.outcome)
      const existing = await prisma.market.findUnique({
        where: { id: params.id },
        select: { creatorName: true },
      })
      if (!existing) {
        set.status = 404
        return { error: 'Market not found' }
      }
      if (existing.creatorName !== user.name) {
        set.status = 403
        return { error: 'Only the market creator can resolve this market' }
      }
      if (!['YES', 'NO'].includes(outcome)) {
        set.status = 400
        return { error: 'Invalid outcome' }
      }

      const resolved = typeof data.resolved === 'boolean' ? data.resolved : undefined
      const market = await prisma.market.update({
        where: { id: params.id },
        data: {
          resolved,
          outcome: outcome || undefined,
        },
      })

      if (resolved && outcome) {
        const allBets = await prisma.bet.findMany({
          where: { marketId: params.id },
          select: {
            id: true,
            userName: true,
            choice: true,
            coins: true,
            price: true,
          },
        })
        const winningBets = allBets.filter((b) => b.choice === outcome)
        const losingBets = allBets.filter((b) => b.choice !== outcome)

        for (const bet of winningBets) {
          const betUser = await prisma.user.findUnique({
            where: { name: bet.userName },
            select: { id: true, coins: true, heldCoins: true },
          })
          if (betUser) {
            const shares = bet.price > 0 ? bet.coins / bet.price : bet.coins
            await prisma.user.update({
              where: { id: betUser.id },
              data: {
                coins: betUser.coins + shares,
                heldCoins: Math.max(0, betUser.heldCoins - bet.coins),
              },
            })
          }
        }

        for (const bet of losingBets) {
          const betUser = await prisma.user.findUnique({
            where: { name: bet.userName },
            select: { id: true, heldCoins: true },
          })
          if (betUser) {
            await prisma.user.update({
              where: { id: betUser.id },
              data: {
                heldCoins: Math.max(0, betUser.heldCoins - bet.coins),
              },
            })
          }
        }
      }

      return market
    } catch {
      set.status = 500
      return { error: 'Failed to update market' }
    }
  })
  .post('/api/bets', async ({ body, request, set }) => {
    try {
      const sessionUser = await getSessionUser(request)
      if (!sessionUser) {
        set.status = 401
        return { error: 'Please sign in to place a bet' }
      }

      const data = asObject(body)
      const marketId = getString(data.marketId)
      const coins = Number(data.coins)
      const choice = getString(data.choice)
      if (!marketId || !['YES', 'NO'].includes(choice) || !Number.isFinite(coins) || coins <= 0) {
        set.status = 400
        return { error: 'Invalid bet request' }
      }

      const market = await prisma.market.findUnique({
        where: { id: marketId },
        select: {
          id: true,
          resolved: true,
          liquidity: true,
          bets: {
            select: {
              choice: true,
              coins: true,
            },
          },
        },
      })

      if (!market) {
        set.status = 404
        return { error: 'Market not found' }
      }
      if (market.resolved) {
        set.status = 400
        return { error: 'Market already resolved' }
      }

      const user = await prisma.user.findUnique({
        where: { id: sessionUser.id },
        select: { id: true, coins: true, heldCoins: true },
      })
      if (!user) {
        set.status = 401
        return { error: 'User not found' }
      }
      if (user.coins < coins) {
        set.status = 400
        return { error: `Insufficient coins. You have ${user.coins.toLocaleString()} available.` }
      }

      const yesVolume = market.bets
        .filter((b) => b.choice === 'YES')
        .reduce((sum, b) => sum + b.coins, 0)
      const noVolume = market.bets
        .filter((b) => b.choice === 'NO')
        .reduce((sum, b) => sum + b.coins, 0)
      const liquidity = market.liquidity || DEFAULT_LIQUIDITY
      const { yesPrice: currentYesPrice, noPrice: currentNoPrice } =
        calculateLMSRPrice(yesVolume, noVolume, liquidity)
      const betPrice = choice === 'YES' ? currentYesPrice : currentNoPrice

      await prisma.$transaction([
        prisma.user.update({
          where: { id: user.id },
          data: {
            coins: user.coins - coins,
            heldCoins: user.heldCoins + coins,
          },
        }),
        prisma.bet.create({
          data: {
            marketId,
            userName: sessionUser.name,
            coins,
            choice,
            price: betPrice,
          },
        }),
      ])

      const newYesVolume = yesVolume + (choice === 'YES' ? coins : 0)
      const newNoVolume = noVolume + (choice === 'NO' ? coins : 0)
      const { yesPrice: newYesPrice, noPrice: newNoPrice } =
        calculateLMSRPrice(newYesVolume, newNoVolume, liquidity)

      await prisma.priceHistory.create({
        data: {
          marketId,
          yesPrice: newYesPrice,
          noPrice: newNoPrice,
        },
      })

      return { success: true }
    } catch {
      set.status = 500
      return { error: 'Failed to place bet' }
    }
  })
  .post('/api/seed', async ({ set }) => {
    try {
      if (isProduction()) {
        set.status = 403
        return { error: 'Sample seed is disabled in production' }
      }

      const count = await prisma.market.count()
      if (count > 0) {
        return { message: 'Database already seeded' }
      }

      for (const marketData of seedMarkets) {
        const market = await prisma.market.create({
          data: marketData,
        })

        await prisma.priceHistory.create({
          data: {
            marketId: market.id,
            yesPrice: 0.5,
            noPrice: 0.5,
          },
        })
      }

      return { message: 'Database seeded successfully' }
    } catch {
      set.status = 500
      return { error: 'Failed to seed database' }
    }
  })

