import { NextRequest, NextResponse } from 'next/server'
import { hashPassword, setSession, validatePassword, validateUsername } from '@/lib/auth'
import { prisma } from '@/lib/prisma'

export async function POST(request: NextRequest) {
  try {
    const { username, password, confirmPassword } = await request.json()
    const name = validateUsername(username || '')
    validatePassword(password || '')
    if (confirmPassword !== undefined && password !== confirmPassword) {
      return NextResponse.json({ error: 'Passwords do not match' }, { status: 400 })
    }

    const existing = await prisma.user.findUnique({ where: { name } })
    if (existing?.passwordHash) {
      return NextResponse.json({ error: 'Username is already taken' }, { status: 409 })
    }

    const user = existing
      ? await prisma.user.update({
          where: { id: existing.id },
          data: { passwordHash: hashPassword(password) },
        })
      : await prisma.user.create({
          data: { name, passwordHash: hashPassword(password), coins: 10000, heldCoins: 0 },
        })

    await setSession(user)
    return NextResponse.json({ id: user.id, name: user.name, coins: user.coins, heldCoins: user.heldCoins })
  } catch (error) {
    return NextResponse.json({ error: error instanceof Error ? error.message : 'Failed to sign up' }, { status: 400 })
  }
}

