import { Elysia } from 'elysia'
import { prisma } from '@/lib/prisma'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import { asObject, getString } from '@/server/http'
import { getSessionUser } from '@/server/session'

export const betRoutes = new Elysia()
  .post('/api/bets', async ({ body, request, set }) => {
    try {
      const sessionUser = await getSessionUser(request)
      if (!sessionUser) {
        set.status = 401
        return { error: 'Please sign in to place a bet' }
      }

      const data = asObject(body)
      const marketId = getString(data.marketId)
      const coins = Number(data.coins)
      const choice = getString(data.choice)
      if (!marketId || !['YES', 'NO'].includes(choice) || !Number.isFinite(coins) || coins <= 0) {
        set.status = 400
        return { error: 'Invalid bet request' }
      }

      const market = await prisma.market.findUnique({
        where: { id: marketId },
        select: {
          id: true,
          resolved: true,
          liquidity: true,
          bets: {
            select: {
              choice: true,
              coins: true,
            },
          },
        },
      })

      if (!market) {
        set.status = 404
        return { error: 'Market not found' }
      }
      if (market.resolved) {
        set.status = 400
        return { error: 'Market already resolved' }
      }

      const user = await prisma.user.findUnique({
        where: { id: sessionUser.id },
        select: { id: true, coins: true, heldCoins: true },
      })
      if (!user) {
        set.status = 401
        return { error: 'User not found' }
      }
      if (user.coins < coins) {
        set.status = 400
        return { error: `Insufficient coins. You have ${user.coins.toLocaleString()} available.` }
      }

      const yesVolume = market.bets
        .filter((b) => b.choice === 'YES')
        .reduce((sum, b) => sum + b.coins, 0)
      const noVolume = market.bets
        .filter((b) => b.choice === 'NO')
        .reduce((sum, b) => sum + b.coins, 0)
      const liquidity = market.liquidity || DEFAULT_LIQUIDITY
      const { yesPrice: currentYesPrice, noPrice: currentNoPrice } =
        calculateLMSRPrice(yesVolume, noVolume, liquidity)
      const betPrice = choice === 'YES' ? currentYesPrice : currentNoPrice

      await prisma.$transaction([
        prisma.user.update({
          where: { id: user.id },
          data: {
            coins: user.coins - coins,
            heldCoins: user.heldCoins + coins,
          },
        }),
        prisma.bet.create({
          data: {
            marketId,
            userName: sessionUser.name,
            coins,
            choice,
            price: betPrice,
          },
        }),
      ])

      const newYesVolume = yesVolume + (choice === 'YES' ? coins : 0)
      const newNoVolume = noVolume + (choice === 'NO' ? coins : 0)
      const { yesPrice: newYesPrice, noPrice: newNoPrice } =
        calculateLMSRPrice(newYesVolume, newNoVolume, liquidity)

      await prisma.priceHistory.create({
        data: {
          marketId,
          yesPrice: newYesPrice,
          noPrice: newNoPrice,
        },
      })

      return { success: true }
    } catch {
      set.status = 500
      return { error: 'Failed to place bet' }
    }
  })

import { Elysia } from 'elysia'
import type { Prisma } from '@prisma/client'
import { prisma } from '@/lib/prisma'
import { getLeaderboard } from '@/lib/leaderboard'
import { isProduction } from '@/lib/env'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import {
  SESSION_COOKIE,
  SESSION_MAX_AGE,
  createSessionToken,
  hashPassword,
  validatePassword,
  validateUsername,
  verifyPassword,
  verifySessionToken,
} from '@/lib/auth-core'

type BodyRecord = Record<string, unknown>

function cacheHeaders(seconds: number) {
  return {
    'Cache-Control': `public, s-maxage=${seconds}, stale-while-revalidate=${seconds * 2}`,
  }
}

function noStoreHeaders() {
  return {
    'Cache-Control': 'private, no-store',
  }
}

function asObject(body: unknown): BodyRecord {
  return body && typeof body === 'object' && !Array.isArray(body) ? body as BodyRecord : {}
}

function getString(value: unknown) {
  return typeof value === 'string' ? value : ''
}

function getCookieValue(request: Request, name: string) {
  const cookieHeader = request.headers.get('cookie')
  if (!cookieHeader) return undefined

  for (const part of cookieHeader.split(';')) {
    const [rawKey, ...rawValue] = part.trim().split('=')
    if (rawKey === name) return decodeURIComponent(rawValue.join('='))
  }

  return undefined
}

function serializeCookie(name: string, value: string, maxAge: number) {
  const parts = [
    `${name}=${encodeURIComponent(value)}`,
    'HttpOnly',
    'SameSite=Lax',
    'Path=/',
    `Max-Age=${maxAge}`,
  ]

  if (process.env.NODE_ENV === 'production') parts.push('Secure')
  return parts.join('; ')
}

function clearCookie(name: string) {
  return serializeCookie(name, '', 0)
}

async function getSessionUser(request: Request) {
  const token = getCookieValue(request, SESSION_COOKIE)
  const payload = verifySessionToken(token)
  if (!payload) return null

  return prisma.user.findUnique({
    where: { id: payload.userId },
    select: { id: true, name: true, coins: true, heldCoins: true },
  })
}

async function getMarkets(searchParams: URLSearchParams) {
  const category = searchParams.get('category')
  const search = searchParams.get('search')
  const status = searchParams.get('status')

  const where: Prisma.MarketWhereInput = {}

  if (category && category !== 'All') {
    where.category = category
  }

  if (search) {
    where.OR = [
      { title: { contains: search, mode: 'insensitive' } },
      { description: { contains: search, mode: 'insensitive' } },
    ]
  }

  if (status === 'resolved') {
    where.resolved = true
  } else if (status === 'active') {
    where.resolved = false
  }

  const markets = await prisma.market.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    select: {
      id: true,
      title: true,
      description: true,
      category: true,
      imageUrl: true,
      endDate: true,
      resolved: true,
      outcome: true,
      multiplier: true,
      liquidity: true,
      optionYesLabel: true,
      optionNoLabel: true,
      creatorName: true,
      createdAt: true,
      bets: {
        select: {
          choice: true,
          coins: true,
        },
      },
    },
  })

  return markets.map((market) => {
    const yesVolume = market.bets
      .filter((b) => b.choice === 'YES')
      .reduce((sum, b) => sum + b.coins, 0)
    const noVolume = market.bets
      .filter((b) => b.choice === 'NO')
      .reduce((sum, b) => sum + b.coins, 0)
    const totalVolume = yesVolume + noVolume
    const liquidity = market.liquidity || DEFAULT_LIQUIDITY
    const { yesPrice, noPrice } = calculateLMSRPrice(yesVolume, noVolume, liquidity)

    return {
      id: market.id,
      title: market.title,
      description: market.description,
      category: market.category,
      imageUrl: market.imageUrl,
      endDate: market.endDate.toISOString(),
      resolved: market.resolved,
      outcome: market.outcome,
      yesPrice: Math.round(yesPrice * 100),
      noPrice: Math.round(noPrice * 100),
      volume: totalVolume,
      multiplier: market.multiplier,
      optionYesLabel: market.optionYesLabel,
      optionNoLabel: market.optionNoLabel,
      creatorName: market.creatorName,
      createdAt: market.createdAt.toISOString(),
    }
  })
}

