import type { PrismaClient } from '@prisma/client'
import { prisma } from '@/lib/prisma'

export const STARTING_COINS = 10000

type BalanceBet = {
  coins: number
  choice: string
  price: number
  market: {
    resolved: boolean
    outcome: string | null
  }
}

type PrismaLike = PrismaClient | Parameters<Parameters<PrismaClient['$transaction']>[0]>[0]

function normalizeCoins(value: number) {
  return Number(value.toFixed(6))
}

export function calculateBalanceFromBets(bets: BalanceBet[]) {
  let coins = STARTING_COINS
  let heldCoins = 0

  for (const bet of bets) {
    coins -= bet.coins

    if (!bet.market.resolved) {
      heldCoins += bet.coins
      continue
    }

    if (bet.market.outcome === bet.choice) {
      coins += bet.price > 0 ? bet.coins / bet.price : bet.coins
    }
  }

  return {
    coins: normalizeCoins(coins),
    heldCoins: normalizeCoins(heldCoins),
  }
}

export async function getUserBalance(userName: string, client: PrismaLike = prisma) {
  const bets = await client.bet.findMany({
    where: { userName },
    select: {
      coins: true,
      choice: true,
      price: true,
      market: {
        select: {
          resolved: true,
          outcome: true,
        },
      },
    },
  })

  return calculateBalanceFromBets(bets)
}

export async function getUserWithBalanceById(userId: string, client: PrismaLike = prisma) {
  const user = await client.user.findUnique({
    where: { id: userId },
    select: { id: true, name: true },
  })
  if (!user) return null

  return {
    ...user,
    ...(await getUserBalance(user.name, client)),
  }
}

export async function getUserWithBalanceByName(userName: string, client: PrismaLike = prisma) {
  const user = await client.user.findUnique({
    where: { name: userName },
    select: { id: true, name: true },
  })
  if (!user) return null

  return {
    ...user,
    ...(await getUserBalance(user.name, client)),
  }
}

export async function syncUserBalance(userName: string, client: PrismaLike = prisma) {
  const user = await client.user.findUnique({
    where: { name: userName },
    select: { id: true, name: true },
  })
  if (!user) return null

  const balance = await getUserBalance(user.name, client)
  return client.user.update({
    where: { id: user.id },
    data: balance,
    select: { id: true, name: true, coins: true, heldCoins: true },
  })
}

