import { Elysia } from 'elysia'
import { syncUserBalance } from '@/lib/balances'
import { prisma } from '@/lib/prisma'
import { calculateLMSRPrice, DEFAULT_LIQUIDITY } from '@/lib/pricing'
import { asObject, getString } from '@/server/http'
import { getSessionUser } from '@/server/session'

export const betRoutes = new Elysia()
  .post('/api/bets', async ({ body, request, set }) => {
    try {
      const sessionUser = await getSessionUser(request)
      if (!sessionUser) {
        set.status = 401
        return { error: 'Please sign in to place a bet' }
      }

      const data = asObject(body)
      const marketId = getString(data.marketId)
      const coins = Number(data.coins)
      const choice = getString(data.choice)
      if (!marketId || !['YES', 'NO'].includes(choice) || !Number.isFinite(coins) || coins <= 0) {
        set.status = 400
        return { error: 'Invalid bet request' }
      }

      const market = await prisma.market.findUnique({
        where: { id: marketId },
        select: {
          id: true,
          resolved: true,
          endDate: true,
          liquidity: true,
          bets: {
            select: {
              choice: true,
              coins: true,
            },
          },
        },
      })

      if (!market) {
        set.status = 404
        return { error: 'Market not found' }
      }
      if (market.resolved) {
        set.status = 400
        return { error: 'Market already resolved' }
      }
      if (market.endDate <= new Date()) {
        set.status = 400
        return { error: 'Market betting is closed' }
      }

      const user = await syncUserBalance(sessionUser.name)
      if (!user) {
        set.status = 401
        return { error: 'User not found' }
      }
      if (user.coins < coins) {
        set.status = 400
        return { error: `Insufficient coins. You have ${user.coins.toLocaleString()} available.` }
      }

      const yesVolume = market.bets
        .filter((b) => b.choice === 'YES')
        .reduce((sum, b) => sum + b.coins, 0)
      const noVolume = market.bets
        .filter((b) => b.choice === 'NO')
        .reduce((sum, b) => sum + b.coins, 0)
      const liquidity = market.liquidity || DEFAULT_LIQUIDITY
      const { yesPrice: currentYesPrice, noPrice: currentNoPrice } =
        calculateLMSRPrice(yesVolume, noVolume, liquidity)
      const betPrice = choice === 'YES' ? currentYesPrice : currentNoPrice

      const betPlaced = await prisma.$transaction(async (tx) => {
        const update = await tx.user.updateMany({
          where: {
            id: user.id,
            coins: { gte: coins },
          },
          data: {
            coins: { decrement: coins },
            heldCoins: { increment: coins },
          },
        })

        if (update.count !== 1) return false

        await tx.bet.create({
          data: {
            marketId,
            userName: sessionUser.name,
            coins,
            choice,
            price: betPrice,
          },
        })

        return true
      })

      if (!betPlaced) {
        set.status = 400
        return { error: 'Insufficient coins' }
      }

      const newYesVolume = yesVolume + (choice === 'YES' ? coins : 0)
      const newNoVolume = noVolume + (choice === 'NO' ? coins : 0)
      const { yesPrice: newYesPrice, noPrice: newNoPrice } =
        calculateLMSRPrice(newYesVolume, newNoVolume, liquidity)

      await prisma.priceHistory.create({
        data: {
          marketId,
          yesPrice: newYesPrice,
          noPrice: newNoPrice,
        },
      })

      return { success: true }
    } catch {
      set.status = 500
      return { error: 'Failed to place bet' }
    }
  })

