import { prisma } from '../src/lib/prisma'

const STARTING_COINS = 10000

async function recalculate() {
  console.log('Recalculating all user balances...\n')

  const [users, markets] = await Promise.all([
    prisma.user.findMany(),
    prisma.market.findMany({
      orderBy: { createdAt: 'asc' },
      include: {
        bets: {
          orderBy: { createdAt: 'asc' },
          select: {
            id: true,
            userName: true,
            choice: true,
            coins: true,
            price: true,
          },
        },
      },
    }),
  ])

  const userMap = new Map<string, string>()
  const balances = new Map<string, { coins: number; heldCoins: number }>()

  for (const user of users) {
    userMap.set(user.name, user.id)
    balances.set(user.id, { coins: STARTING_COINS, heldCoins: 0 })
  }

  const orphanedBets: string[] = []

  for (const market of markets) {
    // Step 1: Place all bets (deduct liquid, add to held)
    for (const bet of market.bets) {
      const userId = userMap.get(bet.userName)
      if (!userId) {
        orphanedBets.push(bet.id)
        continue
      }
      const bal = balances.get(userId)!
      bal.coins -= bet.coins
      bal.heldCoins += bet.coins
    }

    // Step 2: Resolve market if it has an outcome
    if (market.resolved && market.outcome) {
      const winningBets = market.bets.filter((b) => b.choice === market.outcome)
      const losingBets = market.bets.filter((b) => b.choice !== market.outcome)

      // Winners get their shares (stake / entry price)
      for (const bet of winningBets) {
        const userId = userMap.get(bet.userName)
        if (!userId) continue
        const bal = balances.get(userId)!
        const shares = bet.price > 0 ? bet.coins / bet.price : bet.coins
        bal.coins += shares
        bal.heldCoins -= bet.coins
      }

      // Losers lose their stake (nothing returned)
      for (const bet of losingBets) {
        const userId = userMap.get(bet.userName)
        if (!userId) continue
        const bal = balances.get(userId)!
        bal.heldCoins -= bet.coins
      }
    }
  }

  // Update all users
  console.log(`Updating ${users.length} users...`)
  for (const user of users) {
    const bal = balances.get(user.id)!
    await prisma.user.update({
      where: { id: user.id },
      data: {
        coins: bal.coins,
        heldCoins: Math.max(0, bal.heldCoins),
      },
    })
  }

  console.log('\nRecalculation complete.')
  console.log(`  Users updated: ${users.length}`)
  console.log(`  Markets processed: ${markets.length}`)
  if (orphanedBets.length > 0) {
    console.log(`  Orphaned bets skipped: ${orphanedBets.length}`)
  }

  // Sanity check
  const allUsers = await prisma.user.findMany()
  const totalCoins = allUsers.reduce((sum, u) => sum + u.coins + u.heldCoins, 0)
  console.log(`\n  Total system net worth: ${totalCoins.toLocaleString()}`)

  await prisma.$disconnect()
}

recalculate()
  .catch((e) => {
    console.error(e)
    process.exit(1)
  })

