import type { PrismaClient } from '@prisma/client'
import { prisma } from '@/lib/prisma'

export const STARTING_COINS = 10000

type BalanceBet = {
  coins: number
  choice: string
  price: number
  market: {
    resolved: boolean
    outcome: string | null
  }
}

type PrismaLike = PrismaClient | Parameters<Parameters<PrismaClient['$transaction']>[0]>[0]

function normalizeCoins(value: number) {
  return Number(value.toFixed(6))
}

export function calculateBalanceFromBets(bets: BalanceBet[]) {
  let coins = STARTING_COINS
  let heldCoins = 0

  for (const bet of bets) {
    coins -= bet.coins

    if (!bet.market.resolved) {
      heldCoins += bet.coins
      continue
    }

    if (bet.market.outcome === bet.choice) {
      coins += bet.price > 0 ? bet.coins / bet.price : bet.coins
    }
  }

  return {
    coins: normalizeCoins(coins),
    heldCoins: normalizeCoins(heldCoins),
  }
}

export async function getUserBalance(userName: string, client: PrismaLike = prisma) {
  const bets = await client.bet.findMany({
    where: { userName },
    select: {
      coins: true,
      choice: true,
      price: true,
      market: {
        select: {
          resolved: true,
          outcome: true,
        },
      },
