import { prisma } from '../src/lib/prisma'
import { calculateBalanceFromBets } from '../src/lib/balances'

async function recalculate() {
  console.log('Recalculating all user balances...\n')

  const [users, bets] = await Promise.all([
    prisma.user.findMany(),
    prisma.bet.findMany({
      select: {
        id: true,
        userName: true,
        choice: true,
        coins: true,
        price: true,
        market: {
          select: {
            resolved: true,
            outcome: true,
          },
        },
      },
    }),
  ])

  const usersByName = new Map(users.map((user) => [user.name, user]))
  const betsByUserName = new Map<string, typeof bets>()
  const orphanedBets: string[] = []

  for (const bet of bets) {
    if (!usersByName.has(bet.userName)) {
      orphanedBets.push(bet.id)
      continue
    }

    const userBets = betsByUserName.get(bet.userName) ?? []
    userBets.push(bet)
    betsByUserName.set(bet.userName, userBets)
  }

  console.log(`Updating ${users.length} users...`)
  for (const user of users) {
    const balance = calculateBalanceFromBets(betsByUserName.get(user.name) ?? [])
    await prisma.user.update({
      where: { id: user.id },
      data: balance,
    })
  }

  console.log('\nRecalculation complete.')
  console.log(`  Users updated: ${users.length}`)
  console.log(`  Bets processed: ${bets.length}`)
  if (orphanedBets.length > 0) {
    console.log(`  Orphaned bets skipped: ${orphanedBets.length}`)
  }

  // Sanity check
  const allUsers = await prisma.user.findMany()
  const totalCoins = allUsers.reduce((sum, u) => sum + u.coins + u.heldCoins, 0)
  console.log(`\n  Total system net worth: ${totalCoins.toLocaleString()}`)

  await prisma.$disconnect()
}

