import { calculateBalanceFromBets, STARTING_COINS } from '@/lib/balances'
import { prisma } from '@/lib/prisma'

export type LeaderboardEntry = {
  rank: number
  id: string
  name: string
  coins: number
  heldCoins: number
  netWorth: number
  profit: number
  profitPct: number
  totalVolume: number
  betCount: number
  activeBetCount: number
  wins: number
  losses: number
}

export async function getLeaderboard(): Promise<LeaderboardEntry[]> {
  const [users, bets] = await Promise.all([
    prisma.user.findMany({
      select: {
        id: true,
        name: true,
        coins: true,
        heldCoins: true,
      },
    }),
    prisma.bet.findMany({
      select: {
        userName: true,
        coins: true,
        choice: true,
        price: true,
        market: {
          select: {
            resolved: true,
            outcome: true,
          },
        },
      },
    }),
  ])

  const statsByName = new Map<
    string,
    Pick<LeaderboardEntry, 'totalVolume' | 'betCount' | 'activeBetCount' | 'wins' | 'losses'> & {
      bets: typeof bets
    }
  >()

  for (const bet of bets) {
    const stats = statsByName.get(bet.userName) || {
      totalVolume: 0,
      betCount: 0,
      activeBetCount: 0,
      wins: 0,
      losses: 0,
      bets: [],
    }

    stats.bets.push(bet)
    stats.totalVolume += bet.coins
    stats.betCount += 1

    if (!bet.market.resolved) {
      stats.activeBetCount += 1
    } else if (bet.market.outcome === bet.choice) {
      stats.wins += 1
    } else {
      stats.losses += 1
    }

    statsByName.set(bet.userName, stats)
  }

  return users
    .map((user) => {
      const stats = statsByName.get(user.name) || {
        totalVolume: 0,
        betCount: 0,
        activeBetCount: 0,
        wins: 0,
        losses: 0,
        bets: [],
      }
      const { bets: userBets, ...publicStats } = stats
      const balance = calculateBalanceFromBets(userBets)
      const netWorth = balance.coins + balance.heldCoins
      const profit = netWorth - STARTING_COINS

      return {
        rank: 0,
        id: user.id,
        name: user.name,
        coins: balance.coins,
        heldCoins: balance.heldCoins,
        netWorth,
        profit,
        profitPct: (profit / STARTING_COINS) * 100,
        ...publicStats,
      }
    })
    .sort((a, b) => {
      if (b.netWorth !== a.netWorth) return b.netWorth - a.netWorth
      if (b.totalVolume !== a.totalVolume) return b.totalVolume - a.totalVolume
      return a.name.localeCompare(b.name)
    })
    .map((entry, index) => ({
      ...entry,
      rank: index + 1,
    }))
}
'use client'

import useSWR, { preload } from 'swr'
import type { MarketSummary, MarketDetail } from './market-types'
import type { LeaderboardEntry } from './leaderboard'

export const LEADERBOARD_KEY = '/api/leaderboard'
export const AUTH_KEY = '/api/auth/me'
export const marketKey = (id: string) => `/api/markets/${id}`

export const fetcher = async (url: string) => {
  const response = await fetch(url, {
    credentials: 'same-origin',
  })

  if (!response.ok) {
    throw new Error(`Request failed for ${url}: ${response.status}`)
  }

  return response.json()
}

// Cache config
const SWRCONFIG = {
  refreshInterval: 0,
  revalidateOnFocus: false,
  revalidateIfStale: false,
  keepPreviousData: true,
  dedupingInterval: 30000,
}

export function useMarkets(search?: string, status?: string) {
  const params = new URLSearchParams()
  if (search) params.set('search', search)
  if (status && status !== 'all') params.set('status', status)
  const key = `/api/markets?${params}`

  return useSWR<MarketSummary[]>(key, fetcher, {
    ...SWRCONFIG,
    revalidateOnFocus: true,
    refreshInterval: 30000, // Refresh every 30s
  })
}

export function useMarket(id: string) {
  return useSWR<MarketDetail>(id && id !== '' ? marketKey(id) : null, fetcher, {
    ...SWRCONFIG,
    revalidateOnFocus: true,
    refreshInterval: 15000,
  })
}

export function useLeaderboard() {
  return useSWR<LeaderboardEntry[]>(LEADERBOARD_KEY, fetcher, {
    ...SWRCONFIG,
    refreshInterval: 60000, // Refresh every 60s
  })
}

export function useTrendingMarkets() {
  return useSWR<MarketSummary[]>('/api/markets?status=active', fetcher, {
    ...SWRCONFIG,
    refreshInterval: 30000,
  })
}

export function useAuth() {
  return useSWR<{ user?: { id: string; name: string; coins: number; heldCoins: number } }>(
