import { Elysia } from 'elysia'
import { hashPassword, validatePassword, validateUsername, verifyPassword } from '@/lib/auth-core'
import { getUserWithBalanceById } from '@/lib/balances'
import { prisma } from '@/lib/prisma'
import { asObject, getString, noStoreHeaders } from '@/server/http'
import { clearSessionCookie, createSessionCookie, getSessionUser } from '@/server/session'

export const authRoutes = new Elysia()
  .get('/api/auth/me', async ({ request, set }) => {
    const user = await getSessionUser(request)
    set.headers = noStoreHeaders()
    return { user }
  })
  .post('/api/auth/sign-in', async ({ body, set }) => {
    try {
      const data = asObject(body)
      const name = validateUsername(getString(data.username))
      const user = await prisma.user.findUnique({ where: { name } })

      if (!user || !verifyPassword(getString(data.password), user.passwordHash)) {
        set.status = 401
        return { error: 'Invalid username or password' }
      }

      set.headers['Set-Cookie'] = createSessionCookie(user)
      return await getUserWithBalanceById(user.id)
    } catch (error) {
      set.status = 400
      return { error: error instanceof Error ? error.message : 'Failed to sign in' }
    }
  })
  .post('/api/auth/sign-up', async ({ body, set }) => {
    try {
      const data = asObject(body)
      const password = getString(data.password)
      const name = validateUsername(getString(data.username))
      validatePassword(password)
      if (data.confirmPassword !== undefined && password !== data.confirmPassword) {
        set.status = 400
        return { error: 'Passwords do not match' }
      }

      const existing = await prisma.user.findUnique({ where: { name } })
      if (existing?.passwordHash) {
        set.status = 409
        return { error: 'Username is already taken' }
      }

      const user = existing
        ? await prisma.user.update({
            where: { id: existing.id },
            data: { passwordHash: hashPassword(password) },
          })
        : await prisma.user.create({
            data: { name, passwordHash: hashPassword(password), coins: 10000, heldCoins: 0 },
          })

      set.headers['Set-Cookie'] = createSessionCookie(user)
      return await getUserWithBalanceById(user.id)
    } catch (error) {
      set.status = 400
      return { error: error instanceof Error ? error.message : 'Failed to sign up' }
    }
  })
  .post('/api/auth/sign-out', ({ set }) => {
    set.headers['Set-Cookie'] = clearSessionCookie()
    return { ok: true }
  })
import {
  SESSION_COOKIE,
  SESSION_MAX_AGE,
  createSessionToken,
  verifySessionToken,
} from '@/lib/auth-core'
import { getUserWithBalanceById } from '@/lib/balances'

function getCookieValue(request: Request, name: string) {
  const cookieHeader = request.headers.get('cookie')
  if (!cookieHeader) return undefined

  for (const part of cookieHeader.split(';')) {
    const [rawKey, ...rawValue] = part.trim().split('=')
    if (rawKey === name) return decodeURIComponent(rawValue.join('='))
  }

  return undefined
}

export function serializeCookie(name: string, value: string, maxAge: number) {
  const parts = [
    `${name}=${encodeURIComponent(value)}`,
    'HttpOnly',
    'SameSite=Lax',
    'Path=/',
    `Max-Age=${maxAge}`,
  ]

  if (process.env.NODE_ENV === 'production') parts.push('Secure')
  return parts.join('; ')
}

export function createSessionCookie(user: { id: string; name: string }) {
  return serializeCookie(
    SESSION_COOKIE,
    createSessionToken({ userId: user.id, name: user.name }),
    SESSION_MAX_AGE
  )
}

export function clearSessionCookie() {
  return serializeCookie(SESSION_COOKIE, '', 0)
}

export async function getSessionUser(request: Request) {
  const token = getCookieValue(request, SESSION_COOKIE)
  const payload = verifySessionToken(token)
  if (!payload) return null

  return getUserWithBalanceById(payload.userId)
}
